using System;
using System.Collections.Generic;
using System.Drawing;
using System.Windows.Forms;

namespace Tunetoon.Forms
{
    public class BossCalcForm : Form
    {
        private static readonly Color BgDark  = Color.FromArgb(30, 30, 30);
        private static readonly Color BgPanel = Color.FromArgb(45, 45, 45);
        private static readonly Color BgInput = Color.FromArgb(55, 55, 55);
        private static readonly Color FgWhite = Color.White;
        private static readonly Color FgGray  = Color.LightGray;
        private static readonly Color Accent  = Color.FromArgb(100, 180, 255);

        // ── Estado ───────────────────────────────────────────────────────────
        private readonly List<(ComboBox Type, NumericUpDown Level, CheckBox V2, Button Remove)> _cjEntries  = new();
        private readonly List<(ComboBox Type, NumericUpDown Level, CheckBox V2, Button Remove)> _ceoEntries = new();
        private FlowLayoutPanel _cjRows, _ceoRows;
        private Label _cjResult, _ceoResult;

        private static readonly string _cjImageB64  = "";
        private static readonly string _ceoImageB64 = "";

        public BossCalcForm()
        {
            Text            = "Boss Calculator";
            FormBorderStyle = FormBorderStyle.Sizable;
            StartPosition   = FormStartPosition.CenterParent;
            MinimumSize     = new Size(780, 520);
            Size            = new Size(920, 640);
            BackColor       = BgDark;
            ForeColor       = FgWhite;
            Font            = new Font("Segoe UI", 9f);

            var main = new TableLayoutPanel
            {
                Dock        = DockStyle.Fill,
                ColumnCount = 2,
                RowCount    = 1,
                BackColor   = BgDark,
                Padding     = new Padding(8),
            };
            main.ColumnStyles.Add(new ColumnStyle(SizeType.Percent, 50f));
            main.ColumnStyles.Add(new ColumnStyle(SizeType.Percent, 50f));

            main.Controls.Add(BuildSide("CJ — Chief Justice",          BossCalcData.CjSuits,  false), 0, 0);
            main.Controls.Add(BuildSide("CEO — Chief Executive Officer", BossCalcData.CeoSuits, true),  1, 0);

            Controls.Add(main);
        }

        private Panel BuildSide(string title, (string Name, int MinLv, int MaxLv)[] suits, bool isCeo)
        {
            var outer = new TableLayoutPanel
            {
                Dock       = DockStyle.Fill,
                ColumnCount = 1,
                RowCount   = 4,
                BackColor  = BgDark,
                Padding    = new Padding(4),
            };
            outer.RowStyles.Add(new RowStyle(SizeType.AutoSize));    // title
            outer.RowStyles.Add(new RowStyle(SizeType.AutoSize));    // quantity selector
            outer.RowStyles.Add(new RowStyle(SizeType.Percent, 100f)); // rows
            outer.RowStyles.Add(new RowStyle(SizeType.AutoSize));    // result

            // Title
            outer.Controls.Add(new Label
            {
                Text      = title,
                Dock      = DockStyle.Fill,
                ForeColor = Accent,
                Font      = new Font("Segoe UI", 10f, FontStyle.Bold),
                Padding   = new Padding(0, 0, 0, 4),
                AutoSize  = true,
            }, 0, 0);

            // ── Quantity selector ─────────────────────────────────────────────
            var qPanel = new FlowLayoutPanel
            {
                FlowDirection = FlowDirection.LeftToRight,
                AutoSize      = true,
                BackColor     = BgDark,
                Margin        = new Padding(0, 0, 0, 6),
                WrapContents  = false,
            };
            qPanel.Controls.Add(new Label
            {
                Text      = "Toons:",
                ForeColor = FgGray,
                AutoSize  = true,
                Margin    = new Padding(0, 4, 6, 0),
            });

            var entries = isCeo ? _ceoEntries : _cjEntries;

            for (int n = 1; n <= 8; n++)
            {
                int count = n;
                var btn = new Button
                {
                    Text      = count.ToString(),
                    Width     = 30,
                    Height    = 26,
                    BackColor = BgPanel,
                    ForeColor = FgWhite,
                    FlatStyle = FlatStyle.Flat,
                    Margin    = new Padding(1, 0, 1, 0),
                };
                btn.FlatAppearance.BorderColor = Color.FromArgb(80, 80, 80);
                btn.Click += (s, e) =>
                {
                    var rows = isCeo ? _ceoRows : _cjRows;
                    SetCount(entries, rows, suits, count);
                    Recalculate();
                };
                qPanel.Controls.Add(btn);
            }

            // Boss image
            string imgB64 = isCeo ? _ceoImageB64 : _cjImageB64;
            if (!string.IsNullOrEmpty(imgB64))
            {
                try
                {
                    var bytes = Convert.FromBase64String(imgB64);
                    using var ms = new System.IO.MemoryStream(bytes);
                    var bmp = new Bitmap(Image.FromStream(ms));
                    // Remove fundo preto: torna pixels escuros transparentes
                    for (int x = 0; x < bmp.Width; x++)
                        for (int y = 0; y < bmp.Height; y++)
                        {
                            var px = bmp.GetPixel(x, y);
                            if (px.R < 30 && px.G < 30 && px.B < 30)
                                bmp.SetPixel(x, y, Color.Transparent);
                        }
                    var pic = new PictureBox
                    {
                        Image    = bmp,
                        Width    = 40,
                        Height   = 26,
                        SizeMode = PictureBoxSizeMode.Zoom,
                        BackColor = Color.Transparent,
                        Margin   = new Padding(6, 0, 0, 0),
                    };
                    qPanel.Controls.Add(pic);
                }
                catch { }
            }
            outer.Controls.Add(qPanel, 0, 1);

            // ── Scroll area ───────────────────────────────────────────────────
            var scroll = new Panel { Dock = DockStyle.Fill, AutoScroll = true, BackColor = BgDark };
            var rows2  = new FlowLayoutPanel
            {
                FlowDirection = FlowDirection.TopDown,
                AutoSize      = true,
                AutoSizeMode  = AutoSizeMode.GrowAndShrink,
                WrapContents  = false,
                BackColor     = BgDark,
                Width         = 420,
            };
            scroll.Controls.Add(rows2);
            outer.Controls.Add(scroll, 0, 2);

            if (isCeo) _ceoRows = rows2; else _cjRows = rows2;

            // ── Result label ──────────────────────────────────────────────────
            var result = new Label
            {
                Dock        = DockStyle.Fill,
                ForeColor   = FgWhite,
                BackColor   = BgPanel,
                Font        = new Font("Segoe UI", 9f),
                Padding     = new Padding(8),
                AutoSize    = true,
                MinimumSize = new Size(0, 90),
                Text        = "Select number of toons above.",
            };
            outer.Controls.Add(result, 0, 3);

            if (isCeo) _ceoResult = result; else _cjResult = result;

            var panel = new Panel { Dock = DockStyle.Fill, BackColor = BgDark };
            panel.Controls.Add(outer);
            return panel;
        }

        // ── Definir quantidade exata de linhas ───────────────────────────────
        private void SetCount(
            List<(ComboBox, NumericUpDown, CheckBox, Button)> entries,
            FlowLayoutPanel rows,
            (string Name, int MinLv, int MaxLv)[] suits,
            int count)
        {
            // Remove excesso
            while (entries.Count > count)
            {
                var last = entries[entries.Count - 1];
                entries.RemoveAt(entries.Count - 1);
                Control parent = last.Item4?.Parent?.Parent; // row panel
                if (parent != null) rows.Controls.Remove(parent);
            }
            // Adiciona faltantes
            while (entries.Count < count)
                AddRow(entries, rows, suits);
        }

        // ── Adicionar uma linha de toon ───────────────────────────────────────
        private void AddRow(
            List<(ComboBox, NumericUpDown, CheckBox, Button)> entries,
            FlowLayoutPanel rows,
            (string Name, int MinLv, int MaxLv)[] suits)
        {
            var row = new FlowLayoutPanel
            {
                FlowDirection = FlowDirection.LeftToRight,
                AutoSize      = true,
                AutoSizeMode  = AutoSizeMode.GrowAndShrink,
                WrapContents  = false,
                BackColor     = BgPanel,
                Margin        = new Padding(0, 0, 0, 3),
                Padding       = new Padding(4, 3, 4, 3),
            };

            var typeCombo = new ComboBox
            {
                DropDownStyle = ComboBoxStyle.DropDownList,
                Width         = 160,
                BackColor     = BgInput,
                ForeColor     = FgWhite,
                FlatStyle     = FlatStyle.Flat,
            };
            foreach (var suit in suits) typeCombo.Items.Add(suit.Name);
            typeCombo.SelectedIndex = 0;

            var levelNum = new NumericUpDown
            {
                Width     = 60,
                BackColor = BgInput,
                ForeColor = FgWhite,
                Minimum   = suits[0].MinLv,
                Maximum   = suits[0].MaxLv,
                Value     = suits[0].MaxLv,
                Margin    = new Padding(2, 0, 2, 0),
            };

            var v2Check = new CheckBox
            {
                Text      = "V2",
                ForeColor = FgWhite,
                AutoSize  = true,
                Margin    = new Padding(4, 2, 0, 0),
            };

            var removeBtn = new Button
            {
                Text      = "✕",
                Width     = 26,
                Height    = 23,
                BackColor = Color.FromArgb(80, 30, 30),
                ForeColor = FgWhite,
                FlatStyle = FlatStyle.Flat,
                Margin    = new Padding(4, 0, 0, 0),
            };
            removeBtn.FlatAppearance.BorderSize = 0;

            void RefreshLevels()
            {
                var suit = suits[typeCombo.SelectedIndex];
                if (v2Check.Checked)
                {
                    levelNum.Enabled = false;
                    levelNum.Value   = suit.MaxLv;
                }
                else
                {
                    levelNum.Enabled = true;
                    levelNum.Minimum = suit.MinLv;
                    levelNum.Maximum = suit.MaxLv;
                    levelNum.Value   = suit.MaxLv;
                }
            }

            RefreshLevels();

            typeCombo.SelectedIndexChanged += (_, __) => { RefreshLevels(); Recalculate(); };
            levelNum.ValueChanged          += (_, __) => Recalculate();
            v2Check.CheckedChanged         += (_, __) => { RefreshLevels(); Recalculate(); };

            var entry = (typeCombo, levelNum, v2Check, removeBtn);
            entries.Add(entry);

            removeBtn.Click += (_, __) =>
            {
                entries.Remove(entry);
                rows.Controls.Remove(row);
                Recalculate();
            };

            row.Controls.Add(typeCombo);
            row.Controls.Add(levelNum);
            row.Controls.Add(v2Check);
            row.Controls.Add(removeBtn);
            rows.Controls.Add(row);
        }

        // ── Recalcular ────────────────────────────────────────────────────────
        private void Recalculate()
        {
            RecalcSide(_cjEntries,  false);
            RecalcSide(_ceoEntries, true);
        }

        private void RecalcSide(
            List<(ComboBox Type, NumericUpDown Level, CheckBox V2, Button Remove)> entries,
            bool isCeo)
        {
            var result = isCeo ? _ceoResult : _cjResult;
            if (result == null) return;

            if (entries.Count == 0)
            {
                result.Text = "Select number of toons above.";
                return;
            }

            int total = 0;
            foreach (var (typeC, levelC, v2C, _) in entries)
            {
                var e = new ToonSuitEntry
                {
                    SuitType  = typeC.SelectedItem?.ToString() ?? "",
                    IsV2      = v2C.Checked,
                    SuitLevel = v2C.Checked ? 50 : (int)levelC.Value,
                };
                total += isCeo ? BossCalcData.GetCeoValue(e) : BossCalcData.GetCjValue(e);
            }

            double avg    = (double)total / entries.Count;
            int    avgInt = (int)Math.Floor(avg);

            if (isCeo)
            {
                var r = BossCalcData.LookupCeo(avgInt);
                result.Text =
                    $"Toons: {entries.Count}   Avg Value: {avg:F2}   Tier: {r.Tier}\n\n" +
                    $"Tables:          {r.Tables}\n" +
                    $"Cogs per Table:  {r.CogsPerTable}\n" +
                    $"Cog Types:       {r.CogTypes}\n" +
                    $"V2.0 Cogs:       {r.V2s}\n" +
                    $"Banquet Timer:   {r.BanquetTime}\n" +
                    $"Reward:          {r.Reward}";
            }
            else
            {
                var r = BossCalcData.LookupCj(avgInt);
                result.Text =
                    $"Toons: {entries.Count}   Avg Value: {avg:F2}   Tier: {r.Tier}\n\n" +
                    $"Gavels:    {r.Gavels}\n" +
                    $"Cogs:      {r.Cogs}\n" +
                    $"Evidence:  {r.Evidence}\n" +
                    $"Toon-Up:   {r.ToonUp}";
            }
        }
    }
}
